mapper.update:
update user
name = #{name}, email = #{email}, phone = #{phone}, avatar = #{avatar}, password = #{password}, role_id = #{roleId}, status = #{status}, update_time = now()
where id = #{id}

mapper.select:
select id, user_id, username, operation, module, method, ip, user_agent, execute_time, status, error_message, create_time
from system_log
where user_id = #{userId}
order by create_time desc
limit #{offset}, #{limit}
